        stub:"",
        mainCode:"package main\n\nimport \"piscine\"\n\nfunc main() {\n\tpiscine.Chunk([]int{}, 10)\n\tpiscine.Chunk([]int{0, 1, 2, 3, 4, 5, 6, 7}, 0)\n\tpiscine.Chunk([]int{0, 1, 2, 3, 4, 5, 6, 7}, 3)\n\tpiscine.Chunk([]int{0, 1, 2, 3, 4, 5, 6, 7}, 5)\n\tpiscine.Chunk([]int{0, 1, 2, 3, 4, 5, 6, 7}, 4)\n}\n",
